// JavaScript-in əsas komponentləri

// Dəyişənlər
let name = 'JavaScript';
const version = 2023;
var oldWay = 'legacy';

// Funksiyalar
function greet(name) {
  return `Hello, ${name}!`;
}

// Arrow funksiya
const multiply = (a, b) => a * b;

// Obyektlər
const person = {
  name: 'John',
  age: 30,
  greet() {
    return `Hi, I'm ${this.name}`;
  }
};

// Massivlər
const colors = ['red', 'green', 'blue'];

console.log(greet('World'));
console.log(multiply(5, 3));
console.log(person.greet());
console.log(colors[0]);

// Modern JavaScript xüsusiyyətləri

// Template literals
const name = 'JavaScript';
const message = `Welcome to ${name}!`;

// Destructuring
const person = {name: 'John', age: 30};
const {name: personName, age} = person;

// Spread operator
const numbers = [1, 2, 3];
const moreNumbers = [...numbers, 4, 5];

// Arrow functions
const add = (a, b) => a + b;

// Classes
class Car {
  constructor(brand) {
    this.brand = brand;
  }

  start() {
    return `${this.brand} is starting...`;
  }
}

const myCar = new Car('Tesla');
console.log(myCar.start());

