// Основные компоненты JavaScript

// Переменные
let name = 'JavaScript';
const version = 2023;
var oldWay = 'legacy';

// Функции
function greet(name) {
  return `Привет, ${name}!`;
}

// Стрелочная функция
const multiply = (a, b) => a * b;

// Объекты
const person = {
  name: 'John',
  age: 30,
  greet() {
    return `Привет, я ${this.name}`;
  }
};

// Массивы
const colors = ['red', 'green', 'blue'];

console.log(greet('Мир'));
console.log(multiply(5, 3));
console.log(person.greet());
console.log(colors[0]);

// Современные возможности JavaScript

// Шаблонные литералы
const name = 'JavaScript';
const message = `Добро пожаловать в ${name}!`;

// Деструктуризация
const person = {name: 'John', age: 30};
const {name: personName, age} = person;

// Оператор spread
const numbers = [1, 2, 3];
const moreNumbers = [...numbers, 4, 5];

// Стрелочные функции
const add = (a, b) => a + b;

// Классы
class Car {
  constructor(brand) {
    this.brand = brand;
  }

  start() {
    return `${this.brand} запускается...`;
  }
}

const myCar = new Car('Tesla');
console.log(myCar.start());

